import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void mixedValid() {
        assertTrue(new Solution().isValid("()[]{}"));
    }

    @Test
    void nestedValid() {
        assertTrue(new Solution().isValid("({[]})"));
    }

    @Test
    void wrongNestingOrder() {
        assertFalse(new Solution().isValid("([)]"));
    }

    @Test
    void unclosedOpener() {
        assertFalse(new Solution().isValid("("));
    }

    @Test
    void unopenedCloser() {
        assertFalse(new Solution().isValid("}"));
    }

    @Test
    void emptyString() {
        assertTrue(new Solution().isValid(""));
    }

    @Test
    void singlePair() {
        assertTrue(new Solution().isValid("[]"));
    }
}
